interface PaymentMethod {
  boolean pay(double amount);
}

class CreditCardPayment implements PaymentMethod {
  public boolean pay(double amount) {
    return amount > 0;
  }
}

class Checkout {
  void complete(PaymentMethod method, double total) {
    if (!method.pay(total)) throw new IllegalStateException("payment failed");
  }
}
